import { useEffect, useRef, useState } from "react";

type Sparkle = {
  id: string;
  x: number;
  y: number;
  size: number;
  rot: number;
  hue: number;
  delayMs: number;
};

const uid = () => `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 9)}`;

export default function ClickSparkles() {
  const [items, setItems] = useState<Sparkle[]>([]);
  const timers = useRef<number[]>([]);

  useEffect(() => {
    return () => {
      for (const t of timers.current) window.clearTimeout(t);
      timers.current = [];
    };
  }, []);

  useEffect(() => {
    const onPointerDown = (e: PointerEvent) => {
      const baseX = e.clientX;
      const baseY = e.clientY;

      const batch: Sparkle[] = Array.from({ length: 8 }).map((_, idx) => {
        const angle = (idx / 8) * Math.PI * 2;
        const radius = 8 + (idx % 3) * 6;
        const x = baseX + Math.cos(angle) * radius;
        const y = baseY + Math.sin(angle) * radius;
        const size = 8 + (idx % 4) * 3;
        const rot = Math.floor(Math.random() * 180);
        const hue = 310 + ((idx * 13) % 60);
        const delayMs = (idx % 4) * 20;
        return { id: uid(), x, y, size, rot, hue, delayMs };
      });

      setItems((prev) => [...prev, ...batch]);
      const removeIds = batch.map((b) => b.id);
      const t = window.setTimeout(() => {
        setItems((prev) => prev.filter((p) => !removeIds.includes(p.id)));
      }, 760);
      timers.current.push(t);
    };

    window.addEventListener("pointerdown", onPointerDown, { passive: true });
    return () => window.removeEventListener("pointerdown", onPointerDown);
  }, []);

  return (
    <div aria-hidden className="pointer-events-none fixed inset-0 z-[60]">
      {items.map((s) => (
        <span
          key={s.id}
          className="click-sparkle"
          style={{
            left: s.x,
            top: s.y,
            width: s.size,
            height: s.size,
            transform: `translate(-50%, -50%) rotate(${s.rot}deg)`,
            background: `hsl(${s.hue} 92% 68%)`,
            animationDelay: `${s.delayMs}ms`,
          }}
        />
      ))}
    </div>
  );
}

