import { useEffect, useMemo, useRef, useState } from "react";
import { Music, Volume2, VolumeX } from "lucide-react";
import { cn } from "@/lib/utils";

const STORAGE_KEY = "bg-music-enabled";
const AUDIO_SRC = "/audio/one-less-lonely-girl.mp3";
const DEFAULT_VOLUME = 0.12;

type Status = "idle" | "playing" | "paused" | "blocked";

export default function BackgroundAudio() {
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const [status, setStatus] = useState<Status>("idle");
  const [enabled, setEnabled] = useState<boolean>(() => {
    const v = localStorage.getItem(STORAGE_KEY);
    if (v === "0") return false;
    if (v === "1") return true;
    return true;
  });

  const label = useMemo(() => {
    if (!enabled) return "Música desligada";
    if (status === "playing") return "Música tocando";
    if (status === "paused") return "Música pausada";
    if (status === "blocked") return "Clique pra tocar";
    return "Música";
  }, [enabled, status]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, enabled ? "1" : "0");
  }, [enabled]);

  useEffect(() => {
    if (!enabled) {
      const a = audioRef.current;
      if (a) {
        a.pause();
        setStatus("paused");
      }
      return;
    }

    const audio = new Audio(AUDIO_SRC);
    audio.loop = true;
    audio.volume = DEFAULT_VOLUME;
    audio.preload = "auto";
    audioRef.current = audio;

    const tryPlay = async () => {
      try {
        await audio.play();
        setStatus("playing");
      } catch {
        setStatus("blocked");
      }
    };

    void tryPlay();

    const onFirstGesture = () => {
      if (!enabled) return;
      void tryPlay();
    };

    window.addEventListener("pointerdown", onFirstGesture, { once: true });
    window.addEventListener("keydown", onFirstGesture, { once: true });

    return () => {
      window.removeEventListener("pointerdown", onFirstGesture);
      window.removeEventListener("keydown", onFirstGesture);
      audio.pause();
      audioRef.current = null;
    };
  }, [enabled]);

  const toggleEnabled = () => {
    setEnabled((v) => !v);
  };

  return (
    <div className="fixed bottom-4 right-4 z-[70] flex items-center gap-2">
      <div className="hidden rounded-full border border-pink-200/70 bg-white/80 px-3 py-2 text-xs font-extrabold text-zinc-950/70 shadow-[0_12px_40px_rgba(236,72,153,0.14)] backdrop-blur sm:block">
        {label}
      </div>
      <button
        type="button"
        onClick={toggleEnabled}
        className={cn(
          "inline-flex items-center justify-center gap-2 rounded-full border border-pink-200/70 bg-white/85 px-4 py-3 text-xs font-extrabold text-zinc-950 shadow-[0_12px_40px_rgba(236,72,153,0.18)] backdrop-blur transition",
          "hover:bg-white",
        )}
      >
        <Music className="h-4 w-4 text-pink-500" />
        {enabled ? <Volume2 className="h-4 w-4" /> : <VolumeX className="h-4 w-4" />}
      </button>
    </div>
  );
}

