import { useEffect, useMemo, useRef, useState } from "react";
import { ChevronLeft, ChevronRight } from "lucide-react";
import Dialog from "@/components/Dialog";
import Reveal from "@/components/Reveal";
import { gallery as allGallery } from "@/data/gallery";
import { cn } from "@/lib/utils";

const pickRouletteItems = () => {
  const user = allGallery.filter((g) => g.id.startsWith("u"));
  if (user.length >= 3) return user;
  return allGallery.slice(0, 8);
};

export default function PhotoRoulette() {
  const items = useMemo(() => pickRouletteItems(), []);
  const [index, setIndex] = useState(0);
  const [openId, setOpenId] = useState<string | null>(null);
  const hoverRef = useRef(false);

  const active = items[index] ?? null;
  const selected = openId ? items.find((i) => i.id === openId) ?? null : null;
  const prev = () => setIndex((v) => (v - 1 + items.length) % items.length);
  const next = () => setIndex((v) => (v + 1) % items.length);

  useEffect(() => {
    if (items.length <= 1) return;
    const t = window.setInterval(() => {
      if (hoverRef.current) return;
      setIndex((v) => (v + 1) % items.length);
    }, 3200);
    return () => window.clearInterval(t);
  }, [items.length]);

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (openId) return;
      if (e.key === "ArrowLeft") prev();
      if (e.key === "ArrowRight") next();
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [openId, items.length]);

  return (
    <>
      <div
        className="relative overflow-hidden rounded-[2.25rem] border border-pink-200/80 bg-white/85 p-6 shadow-[0_30px_120px_rgba(236,72,153,0.18)] backdrop-blur-sm sm:p-10"
        onMouseEnter={() => {
          hoverRef.current = true;
        }}
        onMouseLeave={() => {
          hoverRef.current = false;
        }}
      >
        <div className="absolute inset-0 opacity-70">
          <div className="absolute -left-20 top-6 h-44 w-44 rounded-full bg-pink-300/40 blur-3xl" />
          <div className="absolute -right-16 bottom-8 h-52 w-52 rounded-full bg-violet-300/35 blur-3xl" />
        </div>

        <div className="relative grid gap-6 sm:grid-cols-[1fr_auto] sm:items-center sm:gap-10">
          <div className="grid gap-3">
            <Reveal>
              <div className="font-love text-lg text-pink-500">roleta de memórias</div>
            </Reveal>
            <Reveal delayMs={80}>
              <div className="font-display text-3xl text-zinc-950 sm:text-4xl">
                {active?.title ?? "Galeria"}
              </div>
            </Reveal>
            <Reveal delayMs={140}>
              <div className="max-w-xl text-sm font-bold leading-relaxed text-zinc-950/75 sm:text-base">
                {active?.caption ?? "Passeando pelas fotos…"}
              </div>
            </Reveal>
          </div>

          <Reveal delayMs={120}>
            <div className="relative mx-auto w-full max-w-[560px]">
              <div
                className={cn(
                  "relative aspect-[4/5] overflow-hidden rounded-[2.4rem] border border-pink-200/70 bg-white",
                  "shadow-[0_30px_120px_rgba(236,72,153,0.22)]",
                )}
              >
                <button
                  type="button"
                  onClick={() => {
                    if (active) setOpenId(active.id);
                  }}
                  className="group absolute inset-0"
                >
                  {items.map((it, i) => (
                    <img
                      key={it.id}
                      src={it.src}
                      alt={it.title}
                      draggable={false}
                      className={cn(
                        "absolute inset-0 h-full w-full object-cover transition duration-700",
                        i === index ? "opacity-100 scale-100" : "opacity-0 scale-[1.03]",
                      )}
                    />
                  ))}
                  <div className="absolute inset-0 bg-gradient-to-b from-transparent via-transparent to-white/70" />
                  <div className="absolute inset-x-0 bottom-0 p-5">
                    <div className="inline-flex rounded-2xl border border-pink-200/80 bg-white/95 px-4 py-2 text-xs font-extrabold text-zinc-950/80">
                      clique pra abrir
                    </div>
                  </div>
                </button>

                <div className="pointer-events-none absolute inset-0 rounded-[2.4rem] ring-1 ring-pink-300/40" />
              </div>

              <div className="mt-4 flex items-center justify-between gap-3">
                <button type="button" onClick={prev} className="btn-love-ghost px-4 py-2">
                  <ChevronLeft className="h-4 w-4" />
                  voltar
                </button>
                <div className="flex items-center gap-2 overflow-x-auto py-1">
                  {items.map((it, i) => (
                    <button
                      key={it.id}
                      type="button"
                      onClick={() => setIndex(i)}
                      aria-label={it.title}
                      className={cn(
                        "relative h-10 w-10 shrink-0 overflow-hidden rounded-2xl border bg-white shadow-[0_12px_40px_rgba(236,72,153,0.12)] transition",
                        i === index ? "border-pink-300 ring-2 ring-pink-300/40" : "border-pink-200/70",
                      )}
                    >
                      <img src={it.src} alt="" className="h-full w-full object-cover" />
                    </button>
                  ))}
                </div>
                <button type="button" onClick={next} className="btn-love-primary px-4 py-2 text-xs">
                  próxima
                  <ChevronRight className="h-4 w-4" />
                </button>
              </div>
              <div className="mt-2 text-center text-xs font-bold text-zinc-900/45">
                {index + 1} / {items.length}
              </div>
            </div>
          </Reveal>
        </div>
      </div>

      <Dialog open={!!openId} onOpenChange={(v) => setOpenId(v ? openId : null)} title={selected?.title}>
        {openId && selected ? (
          <div className="grid gap-4">
            <div className="overflow-hidden rounded-2xl border border-pink-200/70 bg-white/70">
              <img src={selected.src} alt={selected.title} className="h-auto w-full" />
            </div>
            <div className="text-sm font-bold leading-relaxed text-zinc-950/75">{selected.caption}</div>
          </div>
        ) : null}
      </Dialog>
    </>
  );
}
